import numpy as np

def beta_posterior(alpha, beta, n_heads, n_tails):
    return float(alpha + n_heads), float(beta + n_tails)


def beta_mean(alpha, beta):
    return float(alpha / (alpha + beta))


def _beta_pdf(x, alpha, beta):
    """Unnormalized Beta PDF (sufficient for grid-based CDF)."""
    # Beta PDF: x^(alpha-1) * (1-x)^(beta-1) / B(alpha, beta)
    # Use log for stability
    log_pdf = (alpha - 1) * np.log(np.where(x > 0, x, 1e-300)) + \
              (beta - 1) * np.log(np.where(x < 1, 1 - x, 1e-300))
    return np.exp(log_pdf)


def beta_credible_interval(alpha, beta, ci=0.95):
    x = np.linspace(0, 1, 10000)
    pdf = _beta_pdf(x, alpha, beta)
    # Normalize to get approximate PDF
    pdf = pdf / (np.sum(pdf) * (x[1] - x[0]))
    # Compute CDF via cumulative sum
    cdf = np.cumsum(pdf) * (x[1] - x[0])
    tail = (1 - ci) / 2
    lower = float(x[np.searchsorted(cdf, tail)])
    upper = float(x[np.searchsorted(cdf, 1 - tail)])
    return lower, upper
